import{_ as r,o as e,c as l,ai as t}from"./chunks/framework.ampVZV4B.js";const u=JSON.parse('{"title":"React 生态","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/frontend/react-stack.md","filePath":"tech-system/frontend/react-stack.md"}'),i={name:"tech-system/frontend/react-stack.md"};function o(s,a,n,h,g,d){return e(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="react-生态" tabindex="-1">React 生态 <a class="header-anchor" href="#react-生态" aria-label="Permalink to “React 生态”">​</a></h1><p>React 以其组件化架构和强大的生态系统，成为现代前端开发的主流框架。</p><h2 id="react-基础" tabindex="-1">React 基础 <a class="header-anchor" href="#react-基础" aria-label="Permalink to “React 基础”">​</a></h2><h3 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to “核心概念”">​</a></h3><ul><li><strong>组件</strong>: 函数组件、类组件、JSX语法</li><li><strong>Props</strong>: 属性传递、默认值、类型检查</li><li><strong>State</strong>: 状态管理、setState、状态提升</li><li><strong>生命周期</strong>: 挂载、更新、卸载、错误边界</li></ul><h3 id="react-18-新特性" tabindex="-1">React 18 新特性 <a class="header-anchor" href="#react-18-新特性" aria-label="Permalink to “React 18 新特性”">​</a></h3><ul><li><strong>并发渲染</strong>: Concurrent Mode、Suspense</li><li><strong>自动批处理</strong>: 状态更新批处理</li><li><strong>新的Root API</strong>: createRoot、hydrateRoot</li><li><strong>Suspense</strong>: 数据获取、代码分割</li></ul><h2 id="hooks" tabindex="-1">Hooks <a class="header-anchor" href="#hooks" aria-label="Permalink to “Hooks”">​</a></h2><h3 id="基础hooks" tabindex="-1">基础Hooks <a class="header-anchor" href="#基础hooks" aria-label="Permalink to “基础Hooks”">​</a></h3><ul><li><strong>useState</strong>: 状态管理、初始值</li><li><strong>useEffect</strong>: 副作用、副作用清理</li><li><strong>useContext</strong>: 上下文消费、Provider模式</li><li><strong>useReducer</strong>: 复杂状态、状态机</li></ul><h3 id="额外hooks" tabindex="-1">额外Hooks <a class="header-anchor" href="#额外hooks" aria-label="Permalink to “额外Hooks”">​</a></h3><ul><li><strong>useCallback</strong>: 函数记忆化、依赖优化</li><li><strong>useMemo</strong>: 值记忆化、计算优化</li><li><strong>useRef</strong>: DOM引用、可变引用</li><li><strong>useImperativeHandle</strong>: 命令式API暴露</li></ul><h3 id="自定义hooks" tabindex="-1">自定义Hooks <a class="header-anchor" href="#自定义hooks" aria-label="Permalink to “自定义Hooks”">​</a></h3><ul><li><strong>逻辑复用</strong>: 自定义hooks、组合逻辑</li><li><strong>状态抽象</strong>: 业务逻辑封装</li><li><strong>副作用管理</strong>: 异步操作、事件处理</li></ul><h2 id="状态管理" tabindex="-1">状态管理 <a class="header-anchor" href="#状态管理" aria-label="Permalink to “状态管理”">​</a></h2><h3 id="context-api" tabindex="-1">Context API <a class="header-anchor" href="#context-api" aria-label="Permalink to “Context API”">​</a></h3><ul><li><strong>创建上下文</strong>: createContext、Provider</li><li><strong>消费上下文</strong>: useContext、Consumer</li><li><strong>性能优化</strong>: memo、useMemo</li></ul><h3 id="redux" tabindex="-1">Redux <a class="header-anchor" href="#redux" aria-label="Permalink to “Redux”">​</a></h3><ul><li><strong>状态树</strong>: store、action、reducer</li><li><strong>中间件</strong>: redux-thunk、redux-saga</li><li><strong>选择器</strong>: reselect、状态计算</li><li><strong>DevTools</strong>: 调试工具、时间旅行</li></ul><h3 id="redux-toolkit" tabindex="-1">Redux Toolkit <a class="header-anchor" href="#redux-toolkit" aria-label="Permalink to “Redux Toolkit”">​</a></h3><ul><li><strong>简化Redux</strong>: configureStore、createSlice</li><li><strong>Immer</strong>: 不可变更新、简化语法</li><li><strong>RTK Query</strong>: 数据获取、缓存管理</li></ul><h3 id="zustand" tabindex="-1">Zustand <a class="header-anchor" href="#zustand" aria-label="Permalink to “Zustand”">​</a></h3><ul><li><strong>轻量级</strong>: 小而美、简单API</li><li><strong>TypeScript</strong>: 类型安全、开发体验</li><li><strong>中间件</strong>: 持久化、撤销重做</li></ul><h2 id="路由管理" tabindex="-1">路由管理 <a class="header-anchor" href="#路由管理" aria-label="Permalink to “路由管理”">​</a></h2><h3 id="react-router" tabindex="-1">React Router <a class="header-anchor" href="#react-router" aria-label="Permalink to “React Router”">​</a></h3><ul><li><strong>路由配置</strong>: BrowserRouter、HashRouter</li><li><strong>路由定义</strong>: Route、Routes、嵌套路由</li><li><strong>导航</strong>: Link、NavLink、useNavigate</li><li><strong>参数</strong>: useParams、useSearchParams</li></ul><h3 id="路由守卫" tabindex="-1">路由守卫 <a class="header-anchor" href="#路由守卫" aria-label="Permalink to “路由守卫”">​</a></h3><ul><li><strong>保护路由</strong>: 认证检查、重定向</li><li><strong>懒加载</strong>: React.lazy、Suspense</li><li><strong>代码分割</strong>: 路由级分割</li></ul><h2 id="样式管理" tabindex="-1">样式管理 <a class="header-anchor" href="#样式管理" aria-label="Permalink to “样式管理”">​</a></h2><h3 id="css-in-js" tabindex="-1">CSS in JS <a class="header-anchor" href="#css-in-js" aria-label="Permalink to “CSS in JS”">​</a></h3><ul><li><strong>styled-components</strong>: 样式组件、主题</li><li><strong>emotion</strong>: CSS-in-JS、样式对象</li><li><strong>styled-system</strong>: 设计系统、主题化</li></ul><h3 id="css-modules" tabindex="-1">CSS Modules <a class="header-anchor" href="#css-modules" aria-label="Permalink to “CSS Modules”">​</a></h3><ul><li><strong>局部作用域</strong>: 样式隔离、类名生成</li><li><strong>组合样式</strong>: composes、样式继承</li><li><strong>TypeScript</strong>: 类型定义</li></ul><h3 id="tailwind-css" tabindex="-1">Tailwind CSS <a class="header-anchor" href="#tailwind-css" aria-label="Permalink to “Tailwind CSS”">​</a></h3><ul><li><strong>原子化CSS</strong>: 工具类、响应式设计</li><li><strong>自定义配置</strong>: 主题定制、插件系统</li><li><strong>优化</strong>: PurgeCSS、压缩</li></ul><h2 id="表单处理" tabindex="-1">表单处理 <a class="header-anchor" href="#表单处理" aria-label="Permalink to “表单处理”">​</a></h2><h3 id="受控组件" tabindex="-1">受控组件 <a class="header-anchor" href="#受控组件" aria-label="Permalink to “受控组件”">​</a></h3><ul><li><strong>状态同步</strong>: value、onChange</li><li><strong>表单验证</strong>: 实时验证、错误显示</li><li><strong>提交处理</strong>: preventDefault、表单数据</li></ul><h3 id="react-hook-form" tabindex="-1">React Hook Form <a class="header-anchor" href="#react-hook-form" aria-label="Permalink to “React Hook Form”">​</a></h3><ul><li><strong>高性能</strong>: 最小重渲染、非受控组件</li><li><strong>验证</strong>: 内置验证、自定义规则</li><li><strong>集成</strong>: UI库集成、TypeScript</li></ul><h3 id="formik" tabindex="-1">Formik <a class="header-anchor" href="#formik" aria-label="Permalink to “Formik”">​</a></h3><ul><li><strong>表单状态</strong>: values、errors、touched</li><li><strong>处理函数</strong>: handleChange、handleSubmit</li><li><strong>高级功能</strong>: 数组字段、嵌套表单</li></ul><h2 id="数据获取" tabindex="-1">数据获取 <a class="header-anchor" href="#数据获取" aria-label="Permalink to “数据获取”">​</a></h2><h3 id="fetch-api" tabindex="-1">Fetch API <a class="header-anchor" href="#fetch-api" aria-label="Permalink to “Fetch API”">​</a></h3><ul><li><strong>原生API</strong>: fetch、Response、Request</li><li><strong>错误处理</strong>: try/catch、状态检查</li><li><strong>配置</strong>: headers、credentials、mode</li></ul><h3 id="axios" tabindex="-1">Axios <a class="header-anchor" href="#axios" aria-label="Permalink to “Axios”">​</a></h3><ul><li><strong>HTTP客户端</strong>: 请求配置、拦截器</li><li><strong>实例</strong>: 基础URL、默认配置</li><li><strong>取消请求</strong>: CancelToken、AbortController</li></ul><h3 id="react-query" tabindex="-1">React Query <a class="header-anchor" href="#react-query" aria-label="Permalink to “React Query”">​</a></h3><ul><li><strong>服务端状态</strong>: 缓存、同步、更新</li><li><strong>查询</strong>: useQuery、查询键</li><li><strong>变更</strong>: useMutation、乐观更新</li></ul><h2 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to “性能优化”">​</a></h2><h3 id="渲染优化" tabindex="-1">渲染优化 <a class="header-anchor" href="#渲染优化" aria-label="Permalink to “渲染优化”">​</a></h3><ul><li><strong>React.memo</strong>: 组件记忆化</li><li><strong>useMemo</strong>: 计算结果缓存</li><li><strong>useCallback</strong>: 函数引用稳定</li></ul><h3 id="代码分割" tabindex="-1">代码分割 <a class="header-anchor" href="#代码分割" aria-label="Permalink to “代码分割”">​</a></h3><ul><li><strong>动态导入</strong>: React.lazy、import()</li><li><strong>路由分割</strong>: 按路由分割</li><li><strong>组件分割</strong>: 按组件分割</li></ul><h3 id="虚拟化" tabindex="-1">虚拟化 <a class="header-anchor" href="#虚拟化" aria-label="Permalink to “虚拟化”">​</a></h3><ul><li><strong>长列表</strong>: react-window、react-virtualized</li><li><strong>大数据</strong>: 虚拟滚动、窗口渲染</li></ul><h2 id="测试" tabindex="-1">测试 <a class="header-anchor" href="#测试" aria-label="Permalink to “测试”">​</a></h2><h3 id="单元测试" tabindex="-1">单元测试 <a class="header-anchor" href="#单元测试" aria-label="Permalink to “单元测试”">​</a></h3><ul><li><strong>Jest</strong>: 测试运行器、断言库</li><li><strong>React Testing Library</strong>: 行为测试、用户视角</li><li><strong>测试工具</strong>: render、fireEvent、waitFor</li></ul><h3 id="集成测试" tabindex="-1">集成测试 <a class="header-anchor" href="#集成测试" aria-label="Permalink to “集成测试”">​</a></h3><ul><li><strong>组件测试</strong>: 完整组件、交互测试</li><li><strong>自定义hooks</strong>: hooks测试、状态变化</li><li><strong>上下文测试</strong>: Provider测试、消费测试</li></ul><h3 id="e2e测试" tabindex="-1">E2E测试 <a class="header-anchor" href="#e2e测试" aria-label="Permalink to “E2E测试”">​</a></h3><ul><li><strong>Cypress</strong>: 端到端测试、实时重载</li><li><strong>Playwright</strong>: 跨浏览器、多环境</li><li><strong>Testing Library</strong>: 一致的测试API</li></ul><h2 id="服务端渲染" tabindex="-1">服务端渲染 <a class="header-anchor" href="#服务端渲染" aria-label="Permalink to “服务端渲染”">​</a></h2><h3 id="next-js" tabindex="-1">Next.js <a class="header-anchor" href="#next-js" aria-label="Permalink to “Next.js”">​</a></h3><ul><li><strong>页面路由</strong>: pages目录、动态路由</li><li><strong>数据获取</strong>: getServerSideProps、getStaticProps</li><li><strong>API路由</strong>: api目录、服务端API</li><li><strong>优化</strong>: 图片优化、字体优化</li></ul><h3 id="ssr优化" tabindex="-1">SSR优化 <a class="header-anchor" href="#ssr优化" aria-label="Permalink to “SSR优化”">​</a></h3><ul><li><strong>流式渲染</strong>: 渐进式加载</li><li><strong>缓存策略</strong>: ISR、静态生成</li><li><strong>性能监控</strong>: Web Vitals、Core Web Vitals</li></ul><h2 id="移动端开发" tabindex="-1">移动端开发 <a class="header-anchor" href="#移动端开发" aria-label="Permalink to “移动端开发”">​</a></h2><h3 id="react-native" tabindex="-1">React Native <a class="header-anchor" href="#react-native" aria-label="Permalink to “React Native”">​</a></h3><ul><li><strong>跨平台</strong>: iOS/Android、原生性能</li><li><strong>组件</strong>: View、Text、TouchableOpacity</li><li><strong>导航</strong>: React Navigation、状态管理</li><li><strong>原生模块</strong>: 桥接、原生功能</li></ul><h3 id="expo" tabindex="-1">Expo <a class="header-anchor" href="#expo" aria-label="Permalink to “Expo”">​</a></h3><ul><li><strong>开发工具</strong>: CLI、SDK、构建服务</li><li><strong>托管服务</strong>: EAS Build、EAS Update</li><li><strong>库生态</strong>: Expo SDK、第三方库</li></ul><h2 id="typescript-集成" tabindex="-1">TypeScript 集成 <a class="header-anchor" href="#typescript-集成" aria-label="Permalink to “TypeScript 集成”">​</a></h2><h3 id="类型定义" tabindex="-1">类型定义 <a class="header-anchor" href="#类型定义" aria-label="Permalink to “类型定义”">​</a></h3><ul><li><strong>组件类型</strong>: FC、Props、JSX.Element</li><li><strong>Hooks类型</strong>: useState、useEffect</li><li><strong>事件类型</strong>: React.MouseEvent、React.FormEvent</li></ul><h3 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><strong>严格模式</strong>: strict、noImplicitAny</li><li><strong>类型守卫</strong>: typeof、instanceof</li><li><strong>泛型</strong>: 组件泛型、hooks泛型</li></ul><h2 id="生态工具" tabindex="-1">生态工具 <a class="header-anchor" href="#生态工具" aria-label="Permalink to “生态工具”">​</a></h2><h3 id="开发工具" tabindex="-1">开发工具 <a class="header-anchor" href="#开发工具" aria-label="Permalink to “开发工具”">​</a></h3><ul><li><strong>React DevTools</strong>: 组件树、性能分析</li><li><strong>ESLint</strong>: 代码规范、React规则</li><li><strong>Prettier</strong>: 代码格式化</li></ul><h3 id="辅助库" tabindex="-1">辅助库 <a class="header-anchor" href="#辅助库" aria-label="Permalink to “辅助库”">​</a></h3><ul><li><strong>Lodash</strong>: 工具函数、性能优化</li><li><strong>Moment.js</strong>: 日期处理、格式化</li><li><strong>UUID</strong>: 唯一标识符生成</li></ul><h2 id="企业级应用" tabindex="-1">企业级应用 <a class="header-anchor" href="#企业级应用" aria-label="Permalink to “企业级应用”">​</a></h2><h3 id="项目结构" tabindex="-1">项目结构 <a class="header-anchor" href="#项目结构" aria-label="Permalink to “项目结构”">​</a></h3><ul><li><strong>目录组织</strong>: components、pages、hooks、utils</li><li><strong>代码规范</strong>: ESLint、Prettier、husky</li><li><strong>提交规范</strong>: Commitizen、commitlint</li></ul><h3 id="部署策略" tabindex="-1">部署策略 <a class="header-anchor" href="#部署策略" aria-label="Permalink to “部署策略”">​</a></h3><ul><li><strong>静态部署</strong>: Vercel、Netlify</li><li><strong>容器部署</strong>: Docker、Kubernetes</li><li><strong>CDN优化</strong>: 资源分发、缓存策略</li></ul><h2 id="微前端" tabindex="-1">微前端 <a class="header-anchor" href="#微前端" aria-label="Permalink to “微前端”">​</a></h2><h3 id="架构模式" tabindex="-1">架构模式 <a class="header-anchor" href="#架构模式" aria-label="Permalink to “架构模式”">​</a></h3><ul><li><strong>应用拆分</strong>: 独立部署、团队自治</li><li><strong>路由分发</strong>: 路由劫持、主应用路由</li><li><strong>应用通信</strong>: 事件总线、状态共享</li></ul><h3 id="实现方案" tabindex="-1">实现方案 <a class="header-anchor" href="#实现方案" aria-label="Permalink to “实现方案”">​</a></h3><ul><li><strong>single-spa</strong>: 微前端框架、生命周期</li><li><strong>qiankun</strong>: 基于single-spa、开箱即用</li><li><strong>Module Federation</strong>: Webpack 5、运行时加载</li></ul><h2 id="最佳实践-1" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践-1" aria-label="Permalink to “最佳实践”">​</a></h2><h3 id="代码组织" tabindex="-1">代码组织 <a class="header-anchor" href="#代码组织" aria-label="Permalink to “代码组织”">​</a></h3><ul><li><strong>组件设计</strong>: 组合优于继承、单一职责</li><li><strong>状态管理</strong>: 状态提升、状态下钻</li><li><strong>错误处理</strong>: Error Boundary、错误恢复</li></ul><h3 id="性能监控" tabindex="-1">性能监控 <a class="header-anchor" href="#性能监控" aria-label="Permalink to “性能监控”">​</a></h3><ul><li><strong>指标收集</strong>: 加载时间、交互时间</li><li><strong>错误监控</strong>: Sentry、错误边界</li><li><strong>用户体验</strong>: Core Web Vitals、性能预算</li></ul>',98)])])}const b=r(i,[["render",o]]);export{u as __pageData,b as default};
